+/// Fuse layers 0, 1, and 2 of a DIT butterfly network into a single memory pass.
+///
+/// Extends `dit_fused_layers_0_1` by also incorporating layer 2, processing groups of
+/// 8 consecutive rows and applying all three butterfly layers in registers before writing
+/// back. This saves two memory passes compared to three separate layer passes.
+///
+/// Layer 0: half_block_size=1, block_size=2, twiddle t0
+/// Layer 1: half_block_size=2, block_size=4, twiddles t1_0, t1_1
+/// Layer 2: half_block_size=4, block_size=8, twiddles t2_0..t2_3
+fn dit_fused_layers_0_1_2<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    twiddles: &[Vec<F>],
+    log_h: usize,
+) {
+    let width = submat.width();
+    let t0 = twiddles[log_h - 1][0];
+    let t1_0 = twiddles[log_h - 2][0];
+    let t1_1 = twiddles[log_h - 2][1];
+    let t2_0 = twiddles[log_h - 3][0];
+    let t2_1 = twiddles[log_h - 3][1];
+    let t2_2 = twiddles[log_h - 3][2];
+    let t2_3 = twiddles[log_h - 3][3];
+
+    let t0_p = F::Packing::from(t0);
+    let t1_0_p = F::Packing::from(t1_0);
+    let t1_1_p = F::Packing::from(t1_1);
+    let t2_0_p = F::Packing::from(t2_0);
+    let t2_1_p = F::Packing::from(t2_1);
+    let t2_2_p = F::Packing::from(t2_2);
+    let t2_3_p = F::Packing::from(t2_3);
+
+    for group in submat.values.chunks_mut(8 * width) {
+        let (top4, bot4) = group.split_at_mut(4 * width);
+        let (r01, r23) = top4.split_at_mut(2 * width);
+        let (r0_row, r1_row) = r01.split_at_mut(width);
+        let (r2_row, r3_row) = r23.split_at_mut(width);
+        let (r45, r67) = bot4.split_at_mut(2 * width);
+        let (r4_row, r5_row) = r45.split_at_mut(width);
+        let (r6_row, r7_row) = r67.split_at_mut(width);
+
+        let (r0s, r0x) = F::Packing::pack_slice_with_suffix_mut(r0_row);
+        let (r1s, r1x) = F::Packing::pack_slice_with_suffix_mut(r1_row);
+        let (r2s, r2x) = F::Packing::pack_slice_with_suffix_mut(r2_row);
+        let (r3s, r3x) = F::Packing::pack_slice_with_suffix_mut(r3_row);
+        let (r4s, r4x) = F::Packing::pack_slice_with_suffix_mut(r4_row);
+        let (r5s, r5x) = F::Packing::pack_slice_with_suffix_mut(r5_row);
+        let (r6s, r6x) = F::Packing::pack_slice_with_suffix_mut(r6_row);
+        let (r7s, r7x) = F::Packing::pack_slice_with_suffix_mut(r7_row);
+
+        for (r0, r1, r2, r3, r4, r5, r6, r7) in izip!(
+            r0s.iter_mut(), r1s.iter_mut(), r2s.iter_mut(), r3s.iter_mut(),
+            r4s.iter_mut(), r5s.iter_mut(), r6s.iter_mut(), r7s.iter_mut()
+        ) {
+            // Layer 0: butterfly on pairs (0,1),(2,3),(4,5),(6,7) with t0
+            let t0r1 = *r1 * t0_p;
+            let a0 = *r0 + t0r1;
+            let a1 = *r0 - t0r1;
+            let t0r3 = *r3 * t0_p;
+            let a2 = *r2 + t0r3;
+            let a3 = *r2 - t0r3;
+            let t0r5 = *r5 * t0_p;
+            let a4 = *r4 + t0r5;
+            let a5 = *r4 - t0r5;
+            let t0r7 = *r7 * t0_p;
+            let a6 = *r6 + t0r7;
+            let a7 = *r6 - t0r7;
+
+            // Layer 1: butterfly on (a0,a2) with t1_0, (a1,a3) with t1_1
+            //          and (a4,a6) with t1_0, (a5,a7) with t1_1
+            let t1a2 = a2 * t1_0_p;
+            let b0 = a0 + t1a2;
+            let b2 = a0 - t1a2;
+            let t1a3 = a3 * t1_1_p;
+            let b1 = a1 + t1a3;
+            let b3 = a1 - t1a3;
+            let t1a6 = a6 * t1_0_p;
+            let b4 = a4 + t1a6;
+            let b6 = a4 - t1a6;
+            let t1a7 = a7 * t1_1_p;
+            let b5 = a5 + t1a7;
+            let b7 = a5 - t1a7;
+
+            // Layer 2: butterfly on (b0,b4) with t2_0, (b1,b5) with t2_1,
+            //          (b2,b6) with t2_2, (b3,b7) with t2_3
+            let t2b4 = b4 * t2_0_p;
+            let t2b5 = b5 * t2_1_p;
+            let t2b6 = b6 * t2_2_p;
+            let t2b7 = b7 * t2_3_p;
+            *r0 = b0 + t2b4;
+            *r4 = b0 - t2b4;
+            *r1 = b1 + t2b5;
+            *r5 = b1 - t2b5;
+            *r2 = b2 + t2b6;
+            *r6 = b2 - t2b6;
+            *r3 = b3 + t2b7;
+            *r7 = b3 - t2b7;
+        }
+
+        // Suffix (scalar fallback)
+        for (r0, r1, r2, r3, r4, r5, r6, r7) in izip!(
+            r0x.iter_mut(), r1x.iter_mut(), r2x.iter_mut(), r3x.iter_mut(),
+            r4x.iter_mut(), r5x.iter_mut(), r6x.iter_mut(), r7x.iter_mut()
+        ) {
+            let t0r1 = *r1 * t0;
+            let a0 = *r0 + t0r1; let a1 = *r0 - t0r1;
+            let t0r3 = *r3 * t0;
+            let a2 = *r2 + t0r3; let a3 = *r2 - t0r3;
+            let t0r5 = *r5 * t0;
+            let a4 = *r4 + t0r5; let a5 = *r4 - t0r5;
+            let t0r7 = *r7 * t0;
+            let a6 = *r6 + t0r7; let a7 = *r6 - t0r7;
+            let t1a2 = a2 * t1_0; let b0 = a0 + t1a2; let b2 = a0 - t1a2;
+            let t1a3 = a3 * t1_1; let b1 = a1 + t1a3; let b3 = a1 - t1a3;
+            let t1a6 = a6 * t1_0; let b4 = a4 + t1a6; let b6 = a4 - t1a6;
+            let t1a7 = a7 * t1_1; let b5 = a5 + t1a7; let b7 = a5 - t1a7;
+            let t2b4 = b4 * t2_0; let t2b5 = b5 * t2_1;
+            let t2b6 = b6 * t2_2; let t2b7 = b7 * t2_3;
+            *r0 = b0 + t2b4; *r4 = b0 - t2b4;
+            *r1 = b1 + t2b5; *r5 = b1 - t2b5;
+            *r2 = b2 + t2b6; *r6 = b2 - t2b6;
+            *r3 = b3 + t2b7; *r7 = b3 - t2b7;
+        }
+    }
+}
